  ('police-8b7f1efc-moex-00059', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', 'WhichofthefollowingstatementsisTRUEaccordingtothearticle?', '["AIchatbotsarecurrentlybannedinboththeU.S.andTaiwan", "GeoffreyHintonbelievesAIcanneversurpasshumanintelligence", "GeoffreyHintonwarnedthatAIcouldsurpasshumanintelligenceandposeseriousrisks", "AItoolsareonlyusedbychildrenunderage13"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 59, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00060', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', 'Whatdoesthearticlesuggestabouttheroleoflawenforcementandgovernments?', '["TheyarepromotingtheuseofmoreAIchatbots", "TheyareresponsibleforreplacinghumanrelationshipswithAI", "TheyshouldhelpcreaterulesandmonitorAIusetoprotectusers", "TheyaredevelopingnewAIchatbotsforchildren"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 60, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00061', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'essay', '司法警察官甲正在調查某 A 製造槍枝之案件，為了追查製造槍枝之
處所，數度跟蹤 A，但很快被機警的 A 發現並技巧性的擺脫跟追，
甲在無計可施的情況下，上網購得全球定位防丟器，在捷運車上趁機
靠近 A 並將全球定位防丟器偷偷置入 A 的手提袋，藉此順利追蹤 A
的行蹤。第二天 A 買了一個新的手提袋，而將原有的手提袋丟棄，
防丟器也因而被一併丟棄失效。第三天，甲索性潛入 A的私人車庫，
將全球定位追蹤器安裝在 A 的轎車保險桿內側，此次順利追蹤 A 的
行動軌跡二個禮拜，終於追蹤到 A 製造槍枝的處所。請就上述甲對
A 所為之各個偵查措施，分別附理由指出合法及不合法之措施。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00062', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'essay', 'A警察為了調查甲殺乙之案件，分別通知犯罪嫌疑人甲和目擊證人丙
到派出所說明，並於案發後即刻前往醫院詢問乙，對甲、乙、丙三人
之詢問均做成筆錄。甲陳述：「凶刀丟棄在某大水溝裡」，A警循線
尋獲該把凶刀，但當初詢問甲時，為了偵查便利，故意不告知甲得保
持緘默及選任辯護人。丙陳述：「有看到甲用刀刺向乙」，但在法院
審理時翻供稱：「未看到甲殺乙」。乙陳述：「是被甲用刀刺中腹部
才受傷的」，法院開庭時，乙因傷重已於醫院死亡。請問上述 A警察
對甲、乙、丙所做的調查筆錄及所尋獲之凶刀有無證據能力？請分別
附理由說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00063', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於犯罪現場之封鎖，下列敘述何者正確？', '["犯罪現場初期封鎖應儘量縮小範圍，以利後續管理；現場人員之進出，不論是警察或其他 人均須指揮官之同意；許可進入現場者，應穿著必要之防護設備，以免破壞跡證", "現場警戒人員除負責警戒封鎖線外，並應觀察圍觀群眾之可疑動靜，蒐集有利破案之情報 線索；必要時，得以照相、錄影或錄音等方式為之", "初抵現場人員應使用帳篷、雨棚或其他物品保全跡證；為避免跡證遭受風吹、雨淋或日曬 等自然力之破壞，應儘速將所有跡證移回警局保存", "現場封鎖應使用封鎖帶、標示牌、警示閃光燈或其他適當器材，必要時並可向法院申請許 可，同步實施交管措施，以保持現場完整"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00064', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於夜間搜索之案例，下列何者是為合法？', '["警方於晚間12點到A所經營之KTV，該KTV門口亮著招牌燈，但實際上已經停止營業， 並且上鎖；警方未確認營業狀態，即破門搜索", "警方下午5點開始在B的住宅進行搜索，晚間7點因故中斷（離開現場），晚間11點再 自行返回繼續搜索", "警方於晚上9點持搜索票到C經營的旅館，雖然大廳仍開燈，但實際上已停止接待顧客， 僅有員工打掃，警方未經負責人同意即進行搜索", "警方下午3點到D所經營之營業中酒吧搜索，搜索進行至晚上8點仍未結束，期間酒吧正 常營業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00065', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於偵查中辯護人之權利，下列敘述何者正確？', '["A 律師到場後，被司法警察以避免影響偵查為由，只准許 A 律師手寫筆記，而僅能記錄 警察的問題，不得記錄犯罪嫌疑人之回答，避免串證", "B 律師到場後，警察允許 B 律師在場協助詢問，並在詢問結束時以口頭說明律師有在場 一事，也讓其協助閱覽筆錄", "C律師到場後，警察准許C律師在場協助詢問，但礙於個資保護，警察堅持只能由犯罪嫌 疑人單獨閱覽警詢筆錄，拒絕讓C律師協助閱覽", "D 律師到場後，警察准許 D 律師在詢問過程中以手寫方式記錄要點，並在詢問結束後協 助犯罪嫌疑人一同閱覽筆錄，也在筆錄記明辯護人在場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00066', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於檢察官與警察間之關係，下列敘述何者正確？', '["二級司法警察官，如警察官長（分局長、刑警大隊長、專業警察大隊長）偵查犯罪時，僅 須依照自己上級長官指示行動，不必直接聯繫檢察官", "檢察官對於司法警察官或司法警察移送之案件，認為調查未完備時，就司法警察的部分可 以直接發回、限時命其補足；但司法警察官之部分，應聯繫其上級處理", "司法警察官知有犯罪嫌疑者，應即開始調查；必要時得封鎖現場，進行即時勘察，但重要 處分仍需依法律規定事先獲得檢察官或法院之核准", "警察機關與檢察機關在行政體系上互不隸屬，警察機關為犯罪偵查專業，在具體案件中有 權獨立決定偵查方向，檢察機關則是作為法律專業，提供法律程序指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
